/**
 * Grąžina kategorijos pavadinimo vertimą esama kalba.
 * Jei pavadinimas nerastas žodyne (pvz. pogrupis) — grąžina originalą be pakeitimų.
 */
function categoryT(name) {
    const lang = currentLangCode();
    const entry = CATEGORY_I18N[name];
    if (!entry) return name;
    return entry[lang] || entry.lt || name;
}


